                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 24, 16, 30, 0, TimeSpan.FromHours(-7)), Description = "Arrived at regional hub", Location = "Fresno, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.FromHours(-7)), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 11, 22, 0, TimeSpan.FromHours(-7)), Description = "Delivered — left at front door", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-3003"] = new Shipment
        {
